export interface PaginationResult {
    hasNextPage: boolean;
    hasPreviousPage: boolean;
    currentPage: number;
    pageSize: number;
    nextPage: () => void;
    previousPage: () => void;
    reset: () => void;
}
export type FormattingOptions = {
    date?: {
        format?: string;
        relative?: boolean;
    };
    dateTime?: {
        format?: string;
        relative?: boolean;
    };
    currency?: {
        addSymbol?: boolean;
    };
};
export type FetchHookOptions = {
    propertiesToFormat?: string[] | 'all';
    formattingOptions?: FormattingOptions;
};
export type CrmSearchFilter = {
    propertyName: string;
    operator: string;
    value?: string | number | boolean;
    values?: (string | number | boolean)[];
    highValue?: string | number | boolean;
};
export type CrmSearchFilterGroup = {
    filters: CrmSearchFilter[];
};
export type CrmSearchSort = {
    propertyName: string;
    direction: 'ASCENDING' | 'DESCENDING';
};
export type FetchCrmSearchRequest = {
    objectType: string;
    properties?: string[];
    query?: string;
    filterGroups?: CrmSearchFilterGroup[];
    sorts?: CrmSearchSort[];
    pageLength?: number;
    after?: string;
};
export type CrmSearchResultItem = {
    objectId: number;
    properties: Record<string, string | null>;
};
export type CrmSearchResponse = {
    results: CrmSearchResultItem[];
    total: number;
    hasMore: boolean;
    after?: string;
};
export type UseCrmSearchOptions = {
    propertiesToFormat?: 'all' | string[];
    formattingOptions?: FetchHookOptions['formattingOptions'];
};
export interface UseCrmSearchResult {
    results: CrmSearchResultItem[];
    total: number;
    error: Error | null;
    isLoading: boolean;
    isRefetching: boolean;
    pagination: PaginationResult;
    refetch: () => Promise<void>;
}
export type CrmPropertiesResponse = {
    [key: string]: string | null;
};
export interface FetchCrmPropertiesResult {
    data: CrmPropertiesResponse;
    cleanup: () => void;
}
export type AssociationResult = {
    toObjectId: number;
    associationTypes: {
        category: string;
        typeId: number;
        label: string;
    }[];
    properties: {
        [key: string]: string | null;
    };
};
export type AssociationsResponse = {
    results: AssociationResult[];
    hasMore: boolean;
    nextOffset: number;
};
export type FetchAssociationsRequest = {
    toObjectType: string;
    properties?: string[];
    pageLength?: number;
    offset?: number;
};
export interface FetchAssociationsResult {
    data: AssociationsResponse;
    cleanup: () => void;
}
